const crypto = require('crypto');

const SALT_LENGTH = 32;
const KEY_LENGTH = 64;
const ITERATIONS = 100000;
const DIGEST = 'sha512';

/**
 * Hashes a password using PBKDF2 with a random salt.
 * @param {string} password - The plaintext password to hash.
 * @returns {Promise<string>} - The hashed password in the format: salt:iterations:hash
 */
function hashPassword(password) {
  return new Promise((resolve, reject) => {
    if (!password || typeof password !== 'string') {
      return reject(new Error('Password must be a non-empty string'));
    }

    const salt = crypto.randomBytes(SALT_LENGTH).toString('hex');

    crypto.pbkdf2(password, salt, ITERATIONS, KEY_LENGTH, DIGEST, (err, derivedKey) => {
      if (err) {
        return reject(err);
      }
      const hash = derivedKey.toString('hex');
      resolve(`${salt}:${ITERATIONS}:${hash}`);
    });
  });
}

/**
 * Verifies a plaintext password against a stored hash.
 * @param {string} password - The plaintext password to verify.
 * @param {string} storedHash - The stored hash in the format: salt:iterations:hash
 * @returns {Promise<boolean>} - True if the password matches, false otherwise.
 */
function verifyPassword(password, storedHash) {
  return new Promise((resolve, reject) => {
    if (!password || typeof password !== 'string') {
      return reject(new Error('Password must be a non-empty string'));
    }

    if (!storedHash || typeof storedHash !== 'string') {
      return reject(new Error('Stored hash must be a non-empty string'));
    }

    const parts = storedHash.split(':');
    if (parts.length !== 3) {
      return reject(new Error('Invalid stored hash format'));
    }

    const [salt, iterations, hash] = parts;
    const iterCount = parseInt(iterations, 10);

    if (isNaN(iterCount) || iterCount <= 0) {
      return reject(new Error('Invalid iteration count in stored hash'));
    }

    crypto.pbkdf2(password, salt, iterCount, KEY_LENGTH, DIGEST, (err, derivedKey) => {
      if (err) {
        return reject(err);
      }

      const derivedHex = derivedKey.toString('hex');

      // Use timing-safe comparison to prevent timing attacks
      const hashBuffer = Buffer.from(hash, 'hex');
      const derivedBuffer = Buffer.from(derivedHex, 'hex');

      if (hashBuffer.length !== derivedBuffer.length) {
        return resolve(false);
      }

      const isMatch = crypto.timingSafeEqual(hashBuffer, derivedBuffer);
      resolve(isMatch);
    });
  });
}

